const results = $input.all();
const query = $('📱 Telegram Trigger').item.json.message.text;
const chatId = $('📱 Telegram Trigger').item.json.message.chat.id;

let context = '';
if (results.length === 0 || !results[0].json.content) {
  context = 'No relevant memories found.';
} else {
  context = results
    .filter(r => r.json && r.json.content)
    .map((r, i) => {
      const similarity = r.json.similarity ? (r.json.similarity * 100).toFixed(1) : 'N/A';
      const content = r.json.content.replace(/\n/g, ' ').replace(/"/g,

).replace(/\*\*/g, '');
      return `Memory${i+1}(${similarity}%): ${content}`;
    })
    .join(' || ');
}

return [{ json: { query, context, chatId, hasResults: results.length > 0 && !!results[0].json.content } }];

