const fileData = $('📥 Get Photo File').item.json;

// file_path can be nested differently
const filePath = fileData.result?.file_path || fileData.file_path;

if (!filePath) {
  throw new Error('file_path not found. Got: ' + JSON.stringify(fileData));
}

const botToken = "YOUR_TELEGRAM_BOT_TOKEN";
const fileUrl = "https://api.telegram.org/file/bot" + botToken + "/" + filePath;

return [{ json: { imageUrl: fileUrl } }];

const userMessage = $input.item.json.message?.text || "";

// Check for remind intent FIRST (before calling AI)
const lowerMsg = userMessage.toLowerCase();

// ✅ NEW - Check for export intent
if (lowerMsg.includes("/export") || 
    lowerMsg.includes("export") || 
    lowerMsg.includes("download") ||
    lowerMsg.includes("backup")) {
  console.log(`Message: "${userMessage}" → Intent: "export" (keyword match)`);
  return [{ json: { ...($input.item.json), intent: "export" } }];
}

if (lowerMsg.includes("remind me") || 
    lowerMsg.includes("reminder") || 
    lowerMsg.includes("set reminder") ||
    lowerMsg.includes("alert me") ||
    lowerMsg.includes("notify me")) {
  console.log(`Message: "${userMessage}" → Intent: "remind" (keyword match)`);
  return [{ json: { ...($input.item.json), intent: "remind" } }];
}

// Check for save intent FIRST (before calling AI)
if (lowerMsg.startsWith("save:") || lowerMsg.startsWith("save :")) {
  console.log(`Message: "${userMessage}" → Intent: "save" (keyword match)`);
  return [{ json: { ...($input.item.json), intent: "save" } }];
}

// Use AI for everything else
const response = await this.helpers.httpRequest({
  method: "POST",
  url: "https://api.groq.com/openai/v1/chat/completions",
  headers: {
    "Content-Type": "application/json",
    "Authorization": "Bearer YOUR_GROQ_API_KEY"
  },
  body: {
    model: "llama-3.3-70b-versatile",
    messages: [
      {
        role: "system",
        content: `You are a classifier for a personal memory bot. Classify user messages into exactly one of four categories. Reply with ONLY one word: save, retrieve, remind, or unknown.

REPLY "remind" when:
- User wants to be reminded at a specific time
- Contains: remind me, reminder, set reminder, alert me
- Examples: "Remind me to call mom at 5pm"

REPLY "save" when:
- User states a fact, preference, or memory
- Message is a statement NOT a question
- Examples: "I love cricket", "my favourite color is blue"

REPLY "retrieve" when:
- User asks a question
- Contains question words: what, who, when, where, how, why
- Examples: "what do I like?", "who is my friend?"

REPLY "unknown" when:
- Greeting: hello, hi, hey
- Commands: /start, /help
- Cannot determine intent

CRITICAL: Reply with ONLY one word, nothing else.`
      },
      {
        role: "user",
        content: userMessage
      }
    ],
    max_tokens: 5,
    temperature: 0
  },
  json: true
});

const rawIntent = response.choices[0].message.content.trim().toLowerCase();
let intent = "unknown";
if (rawIntent.includes("remind")) intent = "remind";
else if (rawIntent.includes("save")) intent = "save";
else if (rawIntent.includes("retrieve")) intent = "retrieve";
else intent = "unknown";

console.log(`Message: "${userMessage}" → Intent: "${intent}"`);
return [{ json: { ...($input.item.json), intent } }];

const message = $input.item.json.message?.text || "";
const chatId = $input.item.json.message?.chat?.id || "";
const username = $input.item.json.message?.from?.username || "";

const response = await this.helpers.httpRequest({
  method: "POST",
  url: "https://api.groq.com/openai/v1/chat/completions",
  headers: {
    "Content-Type": "application/json",
    "Authorization": "Bearer YOUR_GROQ_API_KEY"
  },
  body: {
    model: "llama-3.3-70b-versatile",
    messages: [
      {
        role: "system",
        content: `Extract reminder details from the message. Current time is ${new Date().toISOString()}.

If a clear time is mentioned, reply with ONLY this JSON:
{"has_time": true, "reminder_text": "task here", "remind_at": "2026-03-17T10:00:00.000Z"}

If NO time is mentioned, reply with ONLY this JSON:
{"has_time": false, "reminder_text": "task here"}`
      },
      {
        role: "user",
        content: message
      }
    ],
    max_tokens: 100,
    temperature: 0
  },
  json: true
});

const raw = response.choices[0].message.content.trim();
const clean = raw.replace(/```json|```/g, "").trim();
const parsed = JSON.parse(clean);

if (!parsed.has_time) {
  return [{
    json: {
      ...($input.item.json),
      no_time: true,
      reminder_text: parsed.reminder_text,
      chat_id: String(chatId),
      username: username
    }
  }];
}

return [{
  json: {
    ...($input.item.json),
    no_time: false,
    reminder_text: parsed.reminder_text,
    remind_at: parsed.remind_at,
    chat_id: String(chatId),
    username: username
  }
}];

const chatId = $input.item.json.message.chat.id;

let memories, reminders;

try {
  memories = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://pcmmctpurvagqiyceepq.supabase.co/rest/v1/documents_export?limit=100',
    headers: {
      'apikey': 'YOUR_SUPABASE_SERVICE_ROLE_JWT',
      'Authorization': 'Bearer YOUR_SUPABASE_SERVICE_ROLE_JWT'
    }
  });
} catch(e) {
  throw new Error('Documents fetch failed: ' + e.message);
}

try {
  reminders = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://pcmmctpurvagqiyceepq.supabase.co/rest/v1/reminders?select=id,chat_id,username,message,remind_at,sent,created_at&order=created_at.desc&limit=100',
    headers: {
      'apikey': 'YOUR_SUPABASE_SERVICE_ROLE_JWT',
      'Authorization': 'Bearer YOUR_SUPABASE_SERVICE_ROLE_JWT'
    }
  });
} catch(e) {
  throw new Error('Reminders fetch failed: ' + e.message);
}

const exportData = {
  export_info: {
    exported_at: new Date().toISOString(),
    exported_by: "Nexus-AI",
    version: "1.0",
    total_memories: memories.length,
    total_reminders: reminders.length,
    user_chat_id: String(chatId)
  },
  memories: memories,
  reminders: reminders
};

const jsonString = JSON.stringify(exportData, null, 2);
const fileName = `nexus-brain-backup-${new Date().toISOString().split('T')[0]}.json`;

return [{
  json: {
    chat_id: String(chatId),
    file_content: jsonString,
    file_name: fileName,
    total_memories: memories.length,
    total_reminders: reminders.length
  }
}];
